import numpy as np
def l1_regularization_gradient(w, lambda_reg):
    return lambda_reg * np.sign(w)

def l2_regularization_gradient(w, lambda_reg):
    return lambda_reg * w

def elastic_net_gradient(w, lambda_reg, l1_ratio=0.5):
    return l1_ratio * l1_regularization_gradient(w, lambda_reg) + \
           (1 - l1_ratio) * l2_regularization_gradient(w, lambda_reg)

import numpy as np
def layer_normalization(X, gamma, beta, eps=1e-5):
    mu = np.mean(X, axis=-1, keepdims=True)
    var = np.var(X, axis=-1, keepdims=True)
    X_norm = (X - mu) / np.sqrt(var + eps)
    return gamma * X_norm + beta

import numpy as np
def conv2d(input_img, kernel, stride=1, padding=0):
    if padding > 0:
        input_img = np.pad(input_img, padding, mode='constant')
    h, w = input_img.shape
    kh, kw = kernel.shape
    out_h = (h - kh) // stride + 1
    out_w = (w - kw) // stride + 1
    output = np.zeros((out_h, out_w))
    for i in range(out_h):
        for j in range(out_w):
            output[i, j] = np.sum(
                input_img[i*stride:i*stride+kh, j*stride:j*stride+kw] * kernel
            )
    return output

import numpy as np
def dropout(X, drop_rate=0.5, training=True):
    if not training:
        return X
    mask = np.random.binomial(1, 1 - drop_rate, X.shape)
    return X * mask / (1 - drop_rate)  # inverted dropout

import numpy as np
def gumbel_softmax(logits, temperature=1.0):
    gumbel_noise = -np.log(-np.log(np.random.uniform(0, 1, logits.shape) + 1e-20) + 1e-20)
    y = logits + gumbel_noise
    return np.exp(y/temperature) / np.exp(y/temperature).sum()
